const tg = window.Telegram?.WebApp;
if (tg) { tg.ready(); tg.expand(); }
// Scroll safety: do not block touchmove/touchend globally.
// Telegram's WebView handles one-finger page scrolling best when touch events stay passive.
// Zoom is controlled by the viewport meta and CSS; global preventDefault breaks scrolling on some Android builds.
try { tg?.disableVerticalSwipes?.(); } catch(e) {}
const initData = tg?.initData || '';
function getUrlFlag(name){
  const search=new URLSearchParams(location.search||'');
  if(search.get(name)) return search.get(name);
  const hash=(location.hash||'').replace(/^#/,'');
  try{const hp=new URLSearchParams(hash); if(hp.get(name)) return hp.get(name);}catch(e){}
  return null;
}
const adminFlag = getUrlFlag('admin') || getUrlFlag('mode') || getUrlFlag('startapp') || tg?.initDataUnsafe?.start_param || '';
const isAdminMode = adminFlag === '1' || String(adminFlag).toLowerCase() === 'admin';
let state = null, adminState = null, currentTab = 'home', currentAdminTab = 'dashboard', searchTerm = '', activeCategory = 'all', pendingDialog = null, pendingEdit = null, currentOrderId = null, orderFilter = 'all', lastSpinPrize = null;
let adminUiCards = [], adminUiWallets = [], adminUiRates = [];
const $ = (id) => document.getElementById(id);
const fmt = (n) => `${Number(n || 0).toLocaleString('fa-IR')} تومان`;
const nf = (n) => Number(n || 0).toLocaleString('fa-IR');
const esc = (s) => String(s ?? '').replace(/[&<>'"]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
const textBlock = (s) => esc(s || '').replace(/\n/g,'<br>');
function colorMix(c){return c || '#1d9bf0'}
function applyTheme(data={}){const local=localStorage.getItem('blue_ref_color');const accent=local||data.theme_color||data.settings?.theme_color||'#1d9bf0';document.documentElement.style.setProperty('--accent',accent);document.documentElement.style.setProperty('--primary',data.button_colors_enabled===false?'#1d9bf0':(data.button_colors?.primary||data.settings?.button_colors?.primary||accent));document.documentElement.style.setProperty('--secondary',data.button_colors?.secondary||data.settings?.button_colors?.secondary||'#2563eb');document.documentElement.style.setProperty('--danger',data.button_colors?.danger||data.settings?.button_colors?.danger||'#ef4444');document.documentElement.style.setProperty('--success',data.button_colors?.success||data.settings?.button_colors?.success||'#22c55e');document.documentElement.style.setProperty('--warning',data.button_colors?.warning||data.settings?.button_colors?.warning||'#f59e0b');tg?.setHeaderColor?.(accent);tg?.setBackgroundColor?.('#08111f');try{tg?.MainButton?.setParams?.({color:accent,text_color:'#ffffff'});}catch(e){}}
function showStatus(text,type='success'){const el=$('status');el.textContent=text;el.className=`toast ${type}`;setTimeout(()=>el.classList.add('hidden'),3500)}
async function api(action,payload={}){const res=await fetch('/api.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action,initData,...payload})});const data=await res.json().catch(()=>({}));if(!res.ok||data.ok===false)throw new Error(data.message||data.error||'خطا در ارتباط');return data}
function openDialog(title,text,placeholder,onSubmit,initial=''){pendingDialog=onSubmit;$('dialogTitle').textContent=title;$('dialogText').textContent=text;$('dialogInput').value=initial;$('dialogInput').placeholder=placeholder||'';$('inputDialog').showModal()}
function openEdit(title,fields,onSubmit){pendingEdit=onSubmit;$('editTitle').textContent=title;$('editFields').innerHTML=fields.join('');$('editDialog').showModal()}
function val(id){const el=$(id);return el?.type==='checkbox'?el.checked:el?.value}
function timeline(t=[]){return t?.length?`<div class="timeline">${t.map(e=>`<div><b>${esc(e.title)}</b><small>${esc(e.created_at||'')}</small></div>`).join('')}</div>`:''}
const cleanupStatuses=['rejected','canceled','refunded'];
function canHideOrder(o){return cleanupStatuses.includes(String(o?.status||''))}
function statusClass(status){return ({delivered:'success',payment_confirmed:'success',preparing:'warning',receipt_submitted:'warning',reviewing:'warning',pending_payment:'pending',rejected:'danger',canceled:'danger',refunded:'danger'}[status]||'pending')}
function orderStatusBadge(o){return `<span class="status-badge ${statusClass(o.status)}">${esc(o.status_fa||o.status)}</span>`}
function orderById(id){return (state.orders||[]).find(o=>Number(o.id)===Number(id))}

function cardImage(obj, emoji='🛒'){return obj.image_url?`<img src="${esc(obj.image_url)}" alt="">`:`<div class="tile-placeholder">${emoji}</div>`}
function priceLabel(p){return esc(p.price_label || fmt(p.price))}
function setTab(tab){currentTab=tab;renderUser()}
function setAdminTab(tab){currentAdminTab=tab;renderAdmin()}
function render(data){state=data;applyTheme(data);$('brandTitle').textContent=data.brand||'BlueReferral';$('helloText').textContent=`سلام ${data.user?.first_name||data.user?.username||'رفیق'} 👋`;$('userApp').classList.toggle('hidden',isAdminMode);$('adminApp').classList.toggle('hidden',!isAdminMode);if(isAdminMode){loadAdmin();return}renderUser()}
function hidePages(){['homePage','shopPage','productPage','ordersPage','walletPage'].forEach(id=>$(id).classList.add('hidden'));document.querySelectorAll('.bottom-nav [data-tab]').forEach(b=>b.classList.toggle('active',b.dataset.tab===currentTab))}
function renderUser(){hidePages();if(currentTab==='home'){ $('homePage').classList.remove('hidden'); renderHome(); }if(currentTab==='shop'){ $('shopPage').classList.remove('hidden'); renderShop(); }if(currentTab==='orders'){ $('ordersPage').classList.remove('hidden'); renderOrders(); }if(currentTab==='wallet'){ $('walletPage').classList.remove('hidden'); renderWallet(); }}
function renderHome(){const u=state.user;const c=u.customer?.tier||{};const today=Number(u.today_referrals||0);$('homePage').innerHTML=`<section class="hero hero-pro wallet-hero"><div class="hero-glow"></div><div class="row"><div><small>داشبورد حساب</small><h2>${esc(u.first_name||u.username||'کاربر BlueReferral')}</h2><p class="muted user-line">${u.username?'@'+esc(u.username):'بدون یوزرنیم'} · ${u.phone_number?'📱 '+esc(u.phone_number):'شماره ثبت نشده'}</p></div><div class="avatar floating-avatar">${u.vip?.emoji||'💙'}</div></div><div class="wallet-balance"><span>موجودی قابل خرج</span><b>${fmt(u.balance)}</b></div><p class="muted">موجودی کیف پولت می‌تواند از مبلغ فاکتور فروشگاه کم شود. سطح همکاری ${u.vip?.emoji||''} ${esc(u.vip?.fa||'')} · سطح مشتری ${c.emoji||''} ${esc(c.fa||'')}</p><div class="actions"><button class="primary pulse" data-tab-jump="shop">🛒 خرج در فروشگاه</button><button class="secondary" id="copyRefHome">🔗 کپی لینک دعوت</button></div></section><div class="stats-grid vivid"><div class="mini-stat"><b>${nf(u.referrals_count)}</b><span>زیرمجموعه</span></div><div class="mini-stat"><b>${fmt(u.total_earned)}</b><span>کل درآمد</span></div><div class="mini-stat"><b>${nf(u.spin_balance)}</b><span>شانس گردونه</span></div></div><article class="mission-preview"> <div><small>ماموریت امروز</small><h3>پیشرفت دعوت‌ها</h3><p class="muted">امروز ${nf(today)} دعوت ثبت شده است.</p></div><button class="secondary" data-tab-jump="wallet">مشاهده</button></article><div class="quick-grid"><button class="quick-card gradient-card" data-tab-jump="orders"><b>🧾 سفارش‌های من</b><span>پیگیری وضعیت و تحویل‌ها</span></button><button class="quick-card gradient-card" data-tab-jump="wallet"><b>💰 کیف پول</b><span>ماموریت، تراکنش و پرداخت</span></button><button class="quick-card gradient-card" data-tab-jump="shop"><b>🛒 فروشگاه</b><span>محصولات دیجیتال و VPN</span></button><button class="quick-card gradient-card" id="paletteQuick"><b>🎨 تغییر رنگ</b><span>ظاهر Mini App را شخصی کن</span></button></div>${renderPalette()}`}
function renderPalette(){const colors=['#1d9bf0','#8b5cf6','#22c55e','#ef4444','#f97316','#ec4899','#06b6d4','#f59e0b','#14b8a6','#64748b'];return `<article class="wallet-card soft-card palette-card"><h3>🎨 رنگ دلخواه Mini App</h3><p class="muted">یکی از رنگ‌ها را بزن یا رنگ اختصاصی خودت را انتخاب کن. این رنگ فقط روی همین دستگاه ذخیره می‌شود.</p><div class="palette">${colors.map(c=>`<button class="swatch" data-color="${c}" style="background:${c}"></button>`).join('')}<label class="custom-color"><span>رنگ دلخواه</span><input id="userCustomColor" type="color" value="${esc(localStorage.getItem('blue_ref_color')||state.theme_color||'#1d9bf0')}"></label><button class="secondary" id="applyCustomColor">اعمال رنگ</button><button class="ghost" id="resetColor">پیش‌فرض</button></div></article>`}
function missionCard(m){const today=Number(state.user?.today_referrals||0);const target=Math.max(1,Number(m.target||1));const pct=Math.max(0,Math.min(100,Math.round(today/target*100)));const done=m.claimed?'claimed':(m.done?'done':'todo');return `<article class="mission-card ${done}"><div class="mission-top"><div><small>${nf(Math.min(today,target))} از ${nf(target)}</small><h3>${nf(target)} دعوت امروز</h3><p class="muted">پاداش: <b>${fmt(m.reward)}</b></p></div><div class="mission-icon">${m.claimed?'✅':(m.done?'🎁':'✌️')}</div></div><div class="progress-track"><span style="width:${pct}%"></span></div><div class="mission-foot"><span>${pct}% تکمیل شده</span><b>${m.claimed?'دریافت شد':(m.done?'آماده دریافت':'در حال انجام')}</b></div></article>`}
function filteredProducts(){return (state.shop_products||[]).filter(p=>(activeCategory==='all'||Number(p.category_id)===Number(activeCategory)||activeCategory==='featured'&&Number(p.is_featured)===1)&&(!searchTerm||`${p.name} ${p.short_description} ${p.full_description}`.toLowerCase().includes(searchTerm.toLowerCase())))}
function shopSectionsHtml(){const cats=state.shop_categories||[];const products=filteredProducts();let sections='';if(activeCategory==='all'&&!searchTerm){const featured=(state.shop_products||[]).filter(p=>Number(p.is_featured)===1);if(featured.length)sections+=sectionHtml('⭐ محصولات ویژه',featured);for(const c of cats){const list=(state.shop_products||[]).filter(p=>Number(p.category_id)===Number(c.id));if(list.length)sections+=sectionHtml(`${esc(c.emoji||'🛒')} ${esc(c.title)}`,list)} }else sections=gridHtml(products);return sections||'<p class="muted empty-state">محصولی پیدا نشد.</p>'}
function renderShop(){const cats=state.shop_categories||[];$('shopPage').innerHTML=`<section class="shop-hero"><div><small>فروشگاه BlueReferral</small><h2>محصولاتو راحت پیدا کن</h2></div><span>🛍</span></section><div class="searchbar">🔍<input id="searchInput" autocomplete="off" inputmode="search" placeholder="جستجوی محصول، اشتراک، VPN..." value="${esc(searchTerm)}"></div><div class="category-strip"><button class="cat-pill ${activeCategory==='all'?'active':''}" data-cat="all"><span>✨</span><b>همه</b></button><button class="cat-pill ${activeCategory==='featured'?'active':''}" data-cat="featured"><span>⭐</span><b>ویژه</b></button>${cats.map(c=>`<button class="cat-pill ${Number(activeCategory)===Number(c.id)?'active':''}" data-cat="${c.id}">${c.image_url?`<img src="${esc(c.image_url)}">`:`<span>${esc(c.emoji||'🛒')}</span>`}<b>${esc(c.title)}</b></button>`).join('')}</div><div id="shopSections">${shopSectionsHtml()}</div>`}
function renderShopSections(){const box=$('shopSections'); if(box) box.innerHTML=shopSectionsHtml();}
function sectionHtml(title,products){return `<section class="section-row"><div class="section-title"><h2>${title}</h2><button data-see-all>مشاهده همه ‹</button></div><div class="h-scroll">${products.map(productCard).join('')}</div></section>`}
function gridHtml(products){return `<section class="section-row"><div class="h-scroll product-grid-wrap">${products.map(productCard).join('')}</div></section>`}
function productCard(p){return `<article class="product-tile" data-product="${p.id}"><div class="tile-img">${cardImage(p,'🛍')}</div><div class="tile-body"><h3>${esc(p.name)}</h3><span class="price-pill">${priceLabel(p)}</span>${Number(p.inventory_available||0)>0?'<span class="soon">آنی</span>':''}</div></article>`}
function buyButtonsForProduct(p){const bal=Number(state.user?.balance||0);const walletHint=bal>0?`<div class="wallet-hint">💰 موجودی شما: <b>${fmt(bal)}</b>؛ می‌تونی ازش برای کم‌کردن فاکتور استفاده کنی.</div>`:'';if((p.variants||[]).length){return `${walletHint}<div class="variant-list">${(p.variants||[]).map(v=>`<div class="variant-card"><div><b>${esc(v.title)}</b><span>${fmt(v.price)}</span></div><button class="primary" data-buy="${p.id}" data-variant="${v.id}">ثبت سفارش</button>${bal>0?`<button class="secondary" data-buy-wallet="${p.id}" data-variant="${v.id}">استفاده از کیف پول</button>`:''}</div>`).join('')}</div>`}return `${walletHint}<div class="actions variant-list"><button class="primary pulse" data-buy="${p.id}">ثبت سفارش</button>${bal>0?`<button class="secondary" data-buy-wallet="${p.id}">خرید با کیف پول</button>`:''}</div>`}
function showProduct(pid){const p=(state.shop_products||[]).find(x=>Number(x.id)===Number(pid));if(!p)return;currentTab='product';hidePages();$('productPage').classList.remove('hidden');$('productPage').innerHTML=`<div class="detail-hero product-hero">${cardImage(p,'🛍')}</div><article class="detail-card product-detail"><button class="secondary" data-back-shop>بازگشت به فروشگاه</button><h2>${esc(p.name)}</h2><div class="product-price-row"><span class="big-price">${priceLabel(p)}</span><span class="badge">${esc(p.delivery_type_fa)}</span><span class="badge">موجودی آماده: ${nf(p.inventory_available||0)}</span></div><div class="description-box">${textBlock(p.full_description||p.short_description||'بدون توضیح')}</div>${buyButtonsForProduct(p)}</article>`}
function renderOrders(){const all=state.orders||[];const filters=[['all','همه'],['active','فعال'],['pending_payment','در انتظار پرداخت'],['receipt_submitted','رسید ارسال شده'],['delivered','تحویل‌شده'],['cleanup','لغو/رد شده']];if(currentOrderId){const o=orderById(currentOrderId); if(!o){currentOrderId=null; return renderOrders()} $('ordersPage').innerHTML=orderDetailHtml(o); return;}const orders=all.filter(o=>orderFilter==='all'||(orderFilter==='active'&&!canHideOrder(o)&&o.status!=='delivered')||(orderFilter==='cleanup'&&canHideOrder(o))||o.status===orderFilter);$('ordersPage').innerHTML=`<section class="orders-header"><div><h2>🧾 سفارش‌های من</h2><p class="muted">روی هر سفارش بزن تا جزئیات تمیز و کاملش باز شود.</p></div><button class="secondary" data-clear-canceled>پاکسازی لغو/رد شده‌ها</button></section><div class="order-filters">${filters.map(f=>`<button class="filter-chip ${orderFilter===f[0]?'active':''}" data-order-filter="${f[0]}">${f[1]}</button>`).join('')}</div><div class="order-list">${orders.map(orderRowHtml).join('')||'<p class="muted empty-state">سفارشی در این بخش نیست.</p>'}</div>`}
function orderRowHtml(o){const paid=Number(o.wallet_amount||0)>0?` · کیف پول ${fmt(o.wallet_amount)}`:'';return `<article class="order-row" data-order-open="${o.id}"><div class="order-row-main"><div class="order-icon">${o.image_url?`<img src="${esc(o.image_url)}">`:'🧾'}</div><div><h3>#${nf(o.id)} · ${esc(o.display_name)}</h3><p class="muted">${esc(o.created_at||'')} · مانده ${fmt(o.final_amount)}${paid}</p></div></div>${orderStatusBadge(o)}<span class="chev">‹</span></article>`}
function paymentMethodsHtml(o){
  const methods=state.payment_methods||{wallet:{enabled:true},card:{enabled:true,accounts:[],instructions:state.payment_instructions||''},stars:{enabled:false,rate_toman:3200},crypto:{enabled:false,wallets:[],markup_percent:1}};
  if(!['pending_payment','rejected'].includes(o.status)||Number(o.final_amount||0)<=0)return '';
  const bal=Number(state.user?.balance||0);
  let html=`<article class="payment-box"><div class="section-title compact"><h3>💳 روش پرداخت</h3><span class="badge">${esc(o.payment_method_fa||'انتخاب نشده')}</span></div><div class="payment-grid">`;
  if(methods.wallet?.enabled) html+=`<button class="pay-method success" data-wallet-order="${o.id}"><b>💰 کیف پول</b><span>موجودی: ${fmt(bal)}</span></button>`;
  if(methods.card?.enabled) html+=`<button class="pay-method" data-select-card="${o.id}"><b>💳 کارت به کارت</b><span>پرداخت دستی با رسید</span></button>`;
  if(methods.stars?.enabled) html+=`<button class="pay-method warning" data-pay-stars="${o.id}"><b>⭐ Telegram Stars</b><span>${nf(Math.max(1,Math.ceil(Number(o.final_amount||0)/Number(methods.stars?.rate_toman||3200))))} استار</span></button>`;
  if(methods.crypto?.enabled) html+=`<button class="pay-method crypto" data-show-crypto="${o.id}"><b>🪙 رمزارز</b><span>USDT / TRX / TON با TXID</span></button>`;
  if(!methods.wallet?.enabled && !methods.card?.enabled && !methods.stars?.enabled && !methods.crypto?.enabled) html+=`<p class="muted empty-state">فعلاً هیچ روش پرداختی فعال نیست. لطفاً به پشتیبانی پیام بده.</p>`;
  html+=`</div>`;
  if(o.payment_method==='card'&&methods.card?.accounts?.length){
    html+=`<div class="card-pay-list"><p class="muted">یکی از کارت‌های زیر را کپی کن، پرداخت را انجام بده و رسید را ارسال کن.</p>`+methods.card.accounts.map(c=>`<div class="pay-card"><div><b>${esc(c.title||'کارت')}</b><small>${esc(c.owner||'')}</small></div><button class="secondary" data-copy="${esc(c.card||'')}">کپی کارت</button><code>${esc(c.card||'')}</code>${c.sheba?`<small>شبا: ${esc(c.sheba)}</small>`:''}</div>`).join('')+`</div>`;
  }
  const cryptoWallets=methods.crypto?.wallets||[];
  const cryptoCheck=o.crypto_check||null;
  if(methods.crypto?.enabled && (o.payment_method==='crypto' || cryptoWallets.length)){
    html+=`<div class="crypto-pay-panel"><h4>🪙 پرداخت رمزارز</h4>`;
    if(o.payment_method!=='crypto'){
      html+=`<p class="muted">کیف پول موردنظر را انتخاب کن. مبلغ رمزارز بر اساس نرخ نوبیتکس یا نرخ دستی ادمین محاسبه می‌شود.</p><div class="crypto-wallet-grid">`+cryptoWallets.map(w=>{const rate=Number(w.rate_toman||0);const markup=Number(methods.crypto?.markup_percent||0)/100;const amount=rate>0?((Number(o.final_amount||0)/rate)*(1+markup)).toFixed(6):null;return `<button class="crypto-wallet" data-select-crypto="${o.id}:${w.id}"><b>${esc(w.title||w.asset)}</b><span>${esc(w.network)} · ${esc(w.asset)}</span><em>${amount?`${amount} ${esc(w.asset)}`:'نرخ دستی لازم است'}</em></button>`}).join('')+`</div>`;
    } else if(cryptoCheck){
      html+=`<div class="crypto-invoice"><div><small>شبکه / ارز</small><b>${esc(cryptoCheck.network)} / ${esc(cryptoCheck.asset)}</b></div><div><small>مبلغ</small><b>${Number(cryptoCheck.expected_amount||0).toFixed(6)} ${esc(cryptoCheck.asset)}</b></div><div class="full"><small>آدرس ولت</small><code>${esc(cryptoCheck.address)}</code><button class="secondary" data-copy="${esc(cryptoCheck.address)}">کپی آدرس</button></div>${cryptoCheck.tx_hash?`<div class="full"><small>TXID</small><code>${esc(cryptoCheck.tx_hash)}</code></div>`:''}<div class="full"><small>وضعیت بررسی</small><b>${cryptoCheck.status==='confirmed'?'✅ تایید شده':cryptoCheck.status==='pending'?'در حال بررسی':'در انتظار هش'}</b>${cryptoCheck.fail_reason?`<p class="muted">${esc(cryptoCheck.fail_reason)}</p>`:''}</div></div><div class="actions"><button class="primary" data-crypto-hash="${o.id}">ثبت TXID / Hash</button><button class="secondary" data-check-crypto="${o.id}">بررسی دوباره</button></div>`;
    }
    html+=`</div>`;
  }
  html+=`</article>`;
  return html;
}

function orderDetailHtml(o){const bal=Number(state.user?.balance||0);return `<section class="detail-card order-detail-page"><button class="secondary" data-order-back>بازگشت به سفارش‌ها</button><div class="order-detail-head"><div><small>سفارش #${nf(o.id)}</small><h2>${esc(o.display_name)}</h2></div>${orderStatusBadge(o)}</div><div class="price-panel"><span>مانده قابل پرداخت</span><b>${fmt(o.final_amount)}</b></div><div class="order-money-grid"><p><b>قیمت اصلی</b><br>${fmt(o.amount)}</p><p><b>تخفیف</b><br>${fmt(o.discount_amount||0)}</p><p><b>پرداخت از کیف پول</b><br>${fmt(o.wallet_amount||0)}</p></div><div class="order-info-grid"><p><b>روش پرداخت</b><br>${esc(o.payment_method_fa||'انتخاب نشده')}</p><p><b>نوع تحویل</b><br>${esc(o.delivery_type_fa||'-')}</p><p><b>تاریخ ثبت</b><br>${esc(o.created_at||'-')}</p>${o.expires_at?`<p><b>انقضا</b><br>${esc(o.expires_at)}</p>`:''}</div>${paymentMethodsHtml(o)}${timeline(o.timeline)}${o.payment_note?`<div class="note-box"><b>رسید/توضیح پرداخت:</b><br>${textBlock(o.payment_note)}</div>`:''}${o.customer_note?`<div class="note-box customer"><b>یادداشت شما:</b><br>${textBlock(o.customer_note)}</div>`:''}${o.delivery_text?`<div class="delivery-box clean-delivery">${textBlock(o.delivery_text)}</div>`:''}<div class="actions sticky-actions">${(o.status==='pending_payment'||o.status==='rejected')&&Number(o.final_amount||0)>0?`<button class="primary" data-receipt="${o.id}">ارسال رسید</button>`:''}<button class="secondary" data-customer-note="${o.id}">یادداشت سفارش</button>${o.status==='pending_payment'?`<button class="secondary" data-coupon="${o.id}">کد تخفیف</button><button class="danger" data-cancel="${o.id}">لغو</button>`:''}${canHideOrder(o)?`<button class="danger" data-hide-order="${o.id}">حذف از لیست من</button>`:''}</div></section>`}

function wheelGradient(rewards=[]){const colors=['#1d9bf0','#22c55e','#f59e0b','#8b5cf6','#ec4899','#06b6d4','#ef4444','#84cc16'];const list=rewards.length?rewards:[{title:'جایزه'}];const step=100/list.length;return `conic-gradient(${list.map((_,i)=>`${colors[i%colors.length]} ${i*step}% ${(i+1)*step}%`).join(',')})`}
function wheelPrizeList(rewards=[]){return (rewards||[]).slice(0,8).map(r=>`<div class="wheel-prize"><b>${esc(r.title||'جایزه')}</b><br><span>${Number(r.amount||0)>0?fmt(r.amount):'جایزه دستی'}</span></div>`).join('') || '<p class="muted">جایزه‌ای تعریف نشده.</p>'}
function renderSpinWheel(){const rewards=state.spin_rewards||[];const chances=Number(state.user?.spin_balance||0);return `<article class="wallet-card spin-section"><div class="compact-title"><div><small>گردونه شانس</small><h3>🎡 جایزه ببر</h3></div><span class="badge">${nf(chances)} شانس</span></div><p class="muted">جایزه‌ها توسط ادمین تنظیم می‌شوند. روی گردونه بزن تا بچرخه و جایزه به کیف پولت اضافه شود.</p><div class="wheel-wrap"><div class="wheel-pointer"></div><div id="spinWheel" class="spin-wheel" style="background:${wheelGradient(rewards)}"><div class="wheel-center">SPIN</div></div></div><button id="spinBtn" class="success pulse" ${chances<=0?'disabled':''}>${chances>0?'چرخاندن گردونه':'فعلاً شانسی نداری'}</button><div id="spinResult" class="spin-result ${lastSpinPrize?'':'hidden'}">${lastSpinPrize?`🎉 جایزه آخر شما: <b>${esc(lastSpinPrize.title||'جایزه گردونه')}</b>${Number(lastSpinPrize.amount||0)>0?`<br>به کیف پول اضافه شد: <b>${fmt(lastSpinPrize.amount)}</b>`:''}`:''}</div><div class="wheel-prizes">${wheelPrizeList(rewards)}</div></article>`}
async function doSpinWheel(){const btn=$('spinBtn'), wheel=$('spinWheel'), result=$('spinResult');if(!btn||btn.disabled)return;btn.disabled=true;btn.textContent='در حال چرخش...';if(result)result.classList.add('hidden');const rewards=state.spin_rewards||[];const count=Math.max(1,rewards.length);const start=Number(wheel?.dataset.rot||0);const fakeIndex=Math.floor(Math.random()*count);const degPer=360/count;const target=start + 1440 + (360 - (fakeIndex*degPer + degPer/2));if(wheel){wheel.dataset.rot=String(target);wheel.style.transform=`rotate(${target}deg)`;}try{await new Promise(r=>setTimeout(r,1800));const data=await api('spin');const prize=data.prize||{};state=data;applyTheme(state);const idx=Number(prize.index ?? fakeIndex);const finalRot=start + 2160 + (360 - (idx*degPer + degPer/2));if(wheel){wheel.dataset.rot=String(finalRot);wheel.style.transform=`rotate(${finalRot}deg)`;}await new Promise(r=>setTimeout(r,2400));lastSpinPrize=prize;if(result){result.innerHTML=`🎉 جایزه شما: <b>${esc(prize.title||'جایزه گردونه')}</b>${Number(prize.amount||0)>0?`<br>به کیف پول اضافه شد: <b>${fmt(prize.amount)}</b>`:''}`;result.classList.remove('hidden')}showStatus('جایزه گردونه ثبت شد');renderWallet()}catch(e){showStatus(e.message||'خطا در گردونه','error');btn.disabled=false;btn.textContent='چرخاندن گردونه'}}

function renderWallet(){const u=state.user;const today=Number(u.today_referrals||0);$('walletPage').innerHTML=`<section class="wallet-dashboard"><div class="wallet-card-main"><small>موجودی قابل خرج در فروشگاه</small><strong>${fmt(u.balance)}</strong><p>این موجودی برای کم‌کردن مبلغ سفارش‌های فروشگاه استفاده می‌شود.</p><button class="primary" data-tab-jump="shop">خرج در فروشگاه</button></div><div class="wallet-mini-grid"><div><b>${fmt(u.total_earned)}</b><span>کل درآمد</span></div><div><b>${fmt(u.total_withdrawn)}</b><span>برداشت موفق</span></div><div><b>${nf(u.referrals_count)}</b><span>دعوت موفق</span></div><div><b>${nf(u.spin_balance)}</b><span>شانس گردونه</span></div></div></section><article class="wallet-card referral-card"><h3>🔗 دعوت دوستان</h3><p class="muted">لینک خام نمایش داده نمی‌شود؛ با دکمه زیر کپی کن و برای دوستانت بفرست.</p><button class="secondary" id="copyLink">کپی لینک دعوت</button></article>${renderSpinWheel()}<article class="wallet-card missions-panel"><div class="section-title"><h2>🎯 ماموریت‌های امروز</h2><small>${nf(today)} دعوت امروز</small></div><div class="missions-grid">${(state.missions||[]).map(missionCard).join('')||'<p class="muted">مأموریتی نیست.</p>'}</div><button class="success" id="claimBtn">دریافت پاداش‌های آماده</button></article><article class="wallet-card"><h3>تراکنش‌های اخیر</h3><div class="tx-list">${(state.transactions||[]).map(t=>`<div class="tx-row"><span>${esc(t.description||t.type)}</span><b class="${Number(t.amount)<0?'negative':'positive'}">${fmt(t.amount)}</b><small>${esc(t.created_at)}</small></div>`).join('')||'<p class="muted">تراکنشی نیست.</p>'}</div></article>`}
async function reload(){state=await api('me');applyTheme(state);renderUser()}
function showFatalPanel(message){
  const html=`<section class="hero error-panel"><h2>⚠️ خطا</h2><p class="muted">${esc(message||'خطا در بارگذاری')}</p><button class="primary" id="reloadAdmin">تلاش دوباره</button></section>`;
  if(isAdminMode){$('userApp').classList.add('hidden');$('adminApp').classList.remove('hidden');$('adminContent').innerHTML=html;}
  else {$('userApp').classList.remove('hidden');$('adminApp').classList.add('hidden');$('homePage').innerHTML=html;}
}
async function load(){
  if(!initData){showFatalPanel('Mini App باید داخل تلگرام باز شود.');showStatus('Mini App باید داخل تلگرام باز شود.','error');return}
  try{
    if(isAdminMode){$('userApp').classList.add('hidden');$('adminApp').classList.remove('hidden');await loadAdmin();return}
    render(await api('me'))
  }catch(e){showFatalPanel(e.message);showStatus(e.message,'error')}
}
async function loadAdmin(){try{adminState=await api('admin_summary');applyTheme(adminState.settings||{});renderAdmin()}catch(e){showFatalPanel(e.message);showStatus(e.message,'error')}}
function renderAdmin(){const r=adminState.report||{};$('adminStats').innerHTML=`<div class="mini-stat"><b>${nf(r.today?.c||0)}</b><span>سفارش امروز<br>${fmt(r.today?.s||0)}</span></div><div class="mini-stat"><b>${nf(r.month?.c||0)}</b><span>سفارش ماه<br>${fmt(r.month?.s||0)}</span></div><div class="mini-stat"><b>${nf(r.pending||0)}</b><span>نیازمند اقدام</span></div>`;document.querySelectorAll('[data-admin-tab]').forEach(b=>b.classList.toggle('active',b.dataset.adminTab===currentAdminTab));const fn={dashboard:renderAdminDashboard,products:renderAdminProducts,categories:renderAdminCategories,variants:renderAdminVariants,inventory:renderAdminInventory,orders:renderAdminOrders,settings:renderAdminSettings}[currentAdminTab];$('adminContent').innerHTML=fn?fn():'';setTimeout(()=>{if(currentAdminTab==='settings')initSettingsUi();},0)}
function catOptions(selected=''){return `<option value="">بدون دسته</option>`+(adminState.categories||[]).map(c=>`<option value="${c.id}" ${Number(selected)===Number(c.id)?'selected':''}>${esc(c.emoji||'🛒')} ${esc(c.title)}</option>`).join('')}
function productOptions(selected=''){return (adminState.products||[]).map(p=>`<option value="${p.id}" ${Number(selected)===Number(p.id)?'selected':''}>#${p.id} ${esc(p.name)}</option>`).join('')}
function variantOptions(selected='', productId=null){return `<option value="">بدون پلن</option>`+(adminState.variants||[]).filter(v=>!productId||Number(v.product_id)===Number(productId)).map(v=>`<option value="${v.id}" ${Number(selected)===Number(v.id)?'selected':''}>#${v.id} ${esc(v.product_name)} - ${esc(v.title)}</option>`).join('')}
function renderAdminDashboard(){const top=adminState.report?.top||[];return `<article class="admin-card"><h3>داشبورد فروش</h3><p class="muted">مدیریت سریع فروشگاه، سفارش‌ها، رنگ‌ها و تنظیمات.</p></article><article class="admin-card"><h3>🏆 محصولات پرفروش</h3>${top.map(t=>`<p>${esc(t.name)} — ${nf(t.c)} سفارش — ${fmt(t.s)}</p>`).join('')||'<p class="muted">هنوز فروش تحویل‌شده‌ای ثبت نشده.</p>'}</article>`}
function renderAdminProducts(){return `<article class="admin-card"><h3>➕ افزودن محصول</h3><div class="form-grid"><input id="ap_name" placeholder="نام محصول"><input id="ap_price" placeholder="قیمت تومان" inputmode="numeric"><select id="ap_cat">${catOptions()}</select><select id="ap_delivery"><option value="manual">دستی</option><option value="account">اکانت</option><option value="vpn">VPN / لینک ساب</option><option value="code">کد</option><option value="file">فایل/متن</option></select><select id="ap_commission_type"><option value="none">بدون پورسانت</option><option value="fixed">مبلغ ثابت</option><option value="percent">درصدی</option></select><input id="ap_commission_value" placeholder="مقدار پورسانت"><input id="ap_img" placeholder="لینک عکس محصول"><input id="ap_duration" placeholder="مدت روز"><label class="switch-line">ویژه باشد؟ <input id="ap_featured" type="checkbox"></label><textarea id="ap_short" placeholder="توضیح کوتاه"></textarea><textarea id="ap_full" placeholder="توضیح کامل"></textarea><button class="primary" data-admin-add-product>ثبت محصول</button></div></article>`+(adminState.products||[]).map(p=>`<div class="admin-item"><h4>#${p.id} ${esc(p.name)}</h4><p class="muted">${priceLabel(p)} | ${Number(p.is_active)?'فعال':'غیرفعال'} | ${Number(p.is_featured)?'ویژه':''} | موجودی: ${nf(p.inventory_available||0)}</p><div class="admin-actions"><button data-edit-product="${p.id}">ویرایش کامل</button><button data-admin-toggle-product="${p.id}">${Number(p.is_active)?'غیرفعال':'فعال'}</button><button class="danger" data-admin-delete-product="${p.id}">غیرفعال‌سازی</button><button class="danger" data-admin-hard-delete-product="${p.id}">حذف کامل</button></div></div>`).join('')}
function renderAdminCategories(){return `<article class="admin-card"><h3>➕ افزودن دسته</h3><div class="form-grid"><input id="ac_title" placeholder="نام دسته"><input id="ac_emoji" placeholder="اموجی"><input id="ac_img" placeholder="لینک عکس دسته"><input id="ac_sort" placeholder="ترتیب نمایش"><button class="primary" data-admin-add-category>ثبت دسته</button></div></article>`+(adminState.categories||[]).map(c=>`<div class="admin-item"><h4>#${c.id} ${esc(c.emoji||'')} ${esc(c.title)}</h4><p class="muted">${Number(c.is_active)?'فعال':'غیرفعال'} | ترتیب: ${nf(c.sort_order)}</p><div class="admin-actions"><button data-edit-category="${c.id}">ویرایش کامل</button><button class="danger" data-admin-delete-category="${c.id}">غیرفعال‌سازی</button><button class="danger" data-admin-hard-delete-category="${c.id}">حذف کامل</button></div></div>`).join('')}
function renderAdminVariants(){return `<article class="admin-card"><h3>➕ افزودن پلن</h3><div class="form-grid"><select id="av_product">${productOptions()}</select><input id="av_title" placeholder="نام پلن"><input id="av_price" placeholder="قیمت"><input id="av_duration" placeholder="مدت روز"><input id="av_sort" placeholder="ترتیب"><button class="primary" data-admin-add-variant>ثبت پلن</button></div></article>`+(adminState.variants||[]).map(v=>`<div class="admin-item"><h4>#${v.id} ${esc(v.product_name)} / ${esc(v.title)}</h4><p class="muted">${fmt(v.price)} | ${Number(v.is_active)?'فعال':'غیرفعال'} | مدت: ${nf(v.duration_days)} روز</p><div class="admin-actions"><button data-edit-variant="${v.id}">ویرایش کامل</button><button class="danger" data-admin-delete-variant="${v.id}">غیرفعال‌سازی</button><button class="danger" data-admin-hard-delete-variant="${v.id}">حذف کامل</button></div></div>`).join('')}
function renderAdminInventory(){return `<article class="admin-card"><h3>➕ افزودن انبار</h3><div class="form-grid"><select id="ai_product">${productOptions()}</select><select id="ai_variant">${variantOptions()}</select><textarea id="ai_content" placeholder="هر آیتم یک خط؛ ایمیل/پسورد، لینک ساب، کد یا متن آماده"></textarea><button class="primary" data-admin-add-inventory>ثبت انبار</button></div></article>`+(adminState.inventory||[]).map(i=>`<div class="admin-item"><h4>#${i.id} ${esc(i.product_name)} ${i.variant_title?' / '+esc(i.variant_title):''}</h4><p class="muted">وضعیت: ${esc(i.status)} | ${esc(String(i.content).slice(0,80))}</p><div class="admin-actions"><button data-edit-inventory="${i.id}">ویرایش کامل</button><button class="danger" data-admin-delete-inventory="${i.id}">حذف امن</button><button class="danger" data-admin-hard-delete-inventory="${i.id}">حذف کامل</button></div></div>`).join('')}
function renderAdminOrders(){const c=adminState.cleanup||{};return `<article class="admin-card cleanup-card"><h3>🧹 پاکسازی سفارش‌ها</h3><p class="muted">فقط سفارش‌های لغو/رد/مرجوع قابل حذف کامل هستند.</p><div class="admin-actions"><button class="danger" data-admin-cleanup="all">حذف همه (${nf(c.all||0)})</button><button class="warning" data-admin-cleanup="7">حذف قدیمی‌تر از ۷ روز (${nf(c.older_7||0)})</button><button class="secondary" data-admin-cleanup="30">حذف قدیمی‌تر از ۳۰ روز (${nf(c.older_30||0)})</button></div></article>`+((adminState.orders||[]).map(o=>`<div class="admin-item"><h4>#${o.id} ${esc(o.display_name)}</h4><p class="muted">${esc(o.status_fa)} | ${fmt(o.final_amount)}</p><div class="admin-actions"><button data-admin-status="${o.id}:reviewing">در بررسی</button><button data-admin-status="${o.id}:payment_confirmed">تایید پرداخت</button><button data-admin-status="${o.id}:preparing">آماده‌سازی</button><button data-admin-deliver="${o.id}">تحویل</button><button class="danger" data-admin-status="${o.id}:rejected">رد</button><button class="secondary" data-admin-archive-order="${o.id}">آرشیو</button>${cleanupStatuses.includes(o.status)?`<button class="danger" data-admin-delete-order="${o.id}">حذف کامل</button>`:''}</div>${timeline(o.timeline)}</div>`).join('')||'<p class="muted">سفارشی نیست.</p>')}

function parsePipeLines(text, fields){
  return String(text||'').split(/\r?\n/).map(x=>x.trim()).filter(Boolean).map((line,idx)=>{
    const p=line.split('|').map(v=>v.trim()); const o={_idx:idx}; fields.forEach((f,i)=>o[f]=p[i]||''); return o;
  });
}
function cardLine(c){return [c.title||'',c.card||'',c.owner||'',c.sheba||''].join('|')}
function walletLine(w){return [w.title||'',(w.network||'TRC20').toUpperCase(),(w.asset||'USDT').toUpperCase(),w.address||'',(w.rate_symbol||w.asset||'USDT').toUpperCase(),String(w.is_active??'1'),String(w.sort_order??'99')].join('|')}
function rateLine(r){return [(r.asset||'USDT').toUpperCase(),String(r.rate_toman||'0')].join('|')}
function parseSettingsBuilders(){
  const st=adminState.settings||{};
  adminUiCards=parsePipeLines(st.card_accounts_text||'', ['title','card','owner','sheba']);
  adminUiWallets=parsePipeLines(st.crypto_wallets_text||'', ['title','network','asset','address','rate_symbol','is_active','sort_order']);
  adminUiRates=parsePipeLines(st.crypto_manual_rates_text||'USDT|0\nTRX|0\nTON|0', ['asset','rate_toman']);
}
function paymentListHtml(items,type){
  if(!items.length) return `<div class="empty-state small">هنوز چیزی اضافه نشده.</div>`;
  return `<div class="builder-list">`+items.map((it,i)=>{
    if(type==='card') return `<div class="builder-row"><div><b>${esc(it.title||'کارت')}</b><small>${esc(it.owner||'بدون صاحب کارت')}</small><code>${esc(it.card||'بدون شماره کارت')}</code>${it.sheba?`<small class="ltr">${esc(it.sheba)}</small>`:''}</div><div class="builder-actions"><button class="secondary tiny" data-builder-edit="card:${i}">ویرایش</button><button class="danger tiny" data-builder-del="card:${i}">حذف</button></div></div>`;
    if(type==='wallet') return `<div class="builder-row"><div><b>${esc(it.title||it.asset||'ولت')}</b><small>${esc((it.network||'').toUpperCase())} · ${esc((it.asset||'').toUpperCase())} · ${it.is_active==='0'?'غیرفعال':'فعال'}</small><code>${esc(it.address||'بدون آدرس')}</code><small>نماد نرخ: ${esc((it.rate_symbol||it.asset||'').toUpperCase())} · ترتیب: ${esc(it.sort_order||'99')}</small></div><div class="builder-actions"><button class="secondary tiny" data-builder-edit="wallet:${i}">ویرایش</button><button class="danger tiny" data-builder-del="wallet:${i}">حذف</button></div></div>`;
    return `<div class="builder-row compact"><div><b>${esc((it.asset||'USDT').toUpperCase())}</b><small>نرخ دستی: ${nf(it.rate_toman||0)} تومان</small></div><div class="builder-actions"><button class="secondary tiny" data-builder-edit="rate:${i}">ویرایش</button><button class="danger tiny" data-builder-del="rate:${i}">حذف</button></div></div>`;
  }).join('')+`</div>`;
}
function syncPaymentBuilders(){
  if($('as_cards') && adminUiCards.length) $('as_cards').value=adminUiCards.map(cardLine).join('\n');
  if($('as_crypto_wallets') && adminUiWallets.length) $('as_crypto_wallets').value=adminUiWallets.map(walletLine).join('\n');
  if($('as_crypto_rates') && adminUiRates.length) $('as_crypto_rates').value=adminUiRates.map(rateLine).join('\n');
  if($('cardBuilderList')) $('cardBuilderList').innerHTML=paymentListHtml(adminUiCards,'card');
  if($('walletBuilderList')) $('walletBuilderList').innerHTML=paymentListHtml(adminUiWallets,'wallet');
  if($('rateBuilderList')) $('rateBuilderList').innerHTML=paymentListHtml(adminUiRates,'rate');
}
function initSettingsUi(){ parseSettingsBuilders(); syncPaymentBuilders(); if($('as_crypto_source')) $('as_crypto_source').value=(adminState.settings?.crypto_rate_source||'nobitex'); }
function field(label,html){return `<label><span>${label}</span>${html}</label>`}
function openCardBuilder(index=null){const c=index===null?{}:adminUiCards[index]||{};openEdit(index===null?'افزودن کارت جدید':'ویرایش کارت',[field('عنوان کارت',`<input id="bc_title" value="${esc(c.title||'')}" placeholder="کارت اصلی">`),field('شماره کارت',`<input id="bc_card" value="${esc(c.card||'')}" inputmode="numeric" placeholder="6037...">`),field('نام صاحب کارت',`<input id="bc_owner" value="${esc(c.owner||'')}" placeholder="نام و نام خانوادگی">`),field('شبا اختیاری',`<input id="bc_sheba" value="${esc(c.sheba||'')}" placeholder="IR...">`)],async()=>{const obj={title:val('bc_title'),card:val('bc_card'),owner:val('bc_owner'),sheba:val('bc_sheba')}; if(!obj.card&&!obj.owner) throw new Error('شماره کارت یا صاحب کارت را وارد کن'); if(index===null)adminUiCards.push(obj);else adminUiCards[index]=obj; syncPaymentBuilders(); showStatus('کارت ذخیره شد')})}
function openWalletBuilder(index=null){const w=index===null?{network:'TRC20',asset:'USDT',rate_symbol:'USDT',is_active:'1',sort_order:'99'}:adminUiWallets[index]||{};openEdit(index===null?'افزودن کیف پول رمزارز':'ویرایش کیف پول',[field('عنوان ولت',`<input id="bw_title" value="${esc(w.title||'')}" placeholder="USDT TRC20">`),field('شبکه',`<select id="bw_network"><option value="TRC20">TRC20</option><option value="TRON">TRON</option><option value="TRX">TRX</option><option value="TON">TON</option></select>`),field('ارز',`<input id="bw_asset" value="${esc((w.asset||'USDT').toUpperCase())}" placeholder="USDT">`),field('آدرس ولت',`<textarea id="bw_address" placeholder="آدرس کیف پول">${esc(w.address||'')}</textarea>`),field('نماد نرخ',`<input id="bw_rate" value="${esc((w.rate_symbol||w.asset||'USDT').toUpperCase())}" placeholder="USDT">`),field('ترتیب نمایش',`<input id="bw_sort" value="${esc(w.sort_order||'99')}" inputmode="numeric">`),`<label class="switch-line">فعال باشد؟ <input id="bw_active" type="checkbox" ${String(w.is_active??'1')!=='0'?'checked':''}></label>`],async()=>{const obj={title:val('bw_title'),network:val('bw_network'),asset:val('bw_asset'),address:val('bw_address'),rate_symbol:val('bw_rate'),is_active:val('bw_active')?'1':'0',sort_order:val('bw_sort')}; if(!obj.address) throw new Error('آدرس ولت را وارد کن'); if(index===null)adminUiWallets.push(obj);else adminUiWallets[index]=obj; syncPaymentBuilders(); showStatus('ولت ذخیره شد')});setTimeout(()=>{if($('bw_network'))$('bw_network').value=(w.network||'TRC20').toUpperCase()},0)}
function openRateBuilder(index=null){const r=index===null?{asset:'USDT',rate_toman:'0'}:adminUiRates[index]||{};openEdit(index===null?'افزودن نرخ دستی':'ویرایش نرخ دستی',[field('نماد ارز',`<input id="br_asset" value="${esc((r.asset||'USDT').toUpperCase())}" placeholder="USDT">`),field('قیمت تومان',`<input id="br_rate" value="${esc(r.rate_toman||0)}" inputmode="decimal" placeholder="95000">`)],async()=>{const obj={asset:val('br_asset'),rate_toman:val('br_rate')}; if(!obj.asset) throw new Error('نماد ارز را وارد کن'); if(index===null)adminUiRates.push(obj);else adminUiRates[index]=obj; syncPaymentBuilders(); showStatus('نرخ دستی ذخیره شد')})}
const adminPaletteColors=['#1d9bf0','#2563eb','#8b5cf6','#22c55e','#14b8a6','#f59e0b','#f97316','#ef4444','#ec4899','#64748b'];
function colorPicker(id,value){return `<div class="color-picker-row"><input id="${id}" type="color" value="${esc(value)}"><input id="${id}_text" value="${esc(value)}" placeholder="#1d9bf0" data-color-mirror="${id}"></div>`}
function settingsPalette(target){return `<div class="admin-palette">${adminPaletteColors.map(c=>`<button class="swatch small" data-admin-color="${target}:${c}" style="background:${c}"></button>`).join('')}</div>`}

